#include <vector>
#include <string>
#include <cstring>
#include <algorithm>

using namespace std;

long long solve(long long n, long long k) {
    if (k == 0) {
        return (n >= 1) ? 1 : 0;
    }

    const int max_pd = 60;
    int pd[max_pd + 2];
    memset(pd, 0, sizeof(pd));
    pd[1] = 0;
    for (int i = 2; i <= max_pd; ++i) {
        pd[i] = pd[__builtin_popcount(i)] + 1;
    }

    long long target = k - 1;
    if (target < 0) {
        return 0;
    }

    vector<int> valid_ms;
    for (int m = 1; m <= max_pd; ++m) {
        if (pd[m] == target) {
            valid_ms.push_back(m);
        }
    }

    if (valid_ms.empty()) {
        return 0;
    }

    string s;
    while (n > 0) {
        s.push_back((n & 1) + '0');
        n >>= 1;
    }
    reverse(s.begin(), s.end());
    int len_s = s.size();

    long long total = 0;
    for (int m : valid_ms) {
        long long dp[len_s + 1][len_s + 1][2];
        memset(dp, -1, sizeof(dp));

        function<long long(int, int, int)> dfs = [&](int pos, int cnt, int tight) -> long long {
            if (pos == len_s) {
                return (cnt == m) ? 1 : 0;
            }
            if (dp[pos][cnt][tight] != -1) {
                return dp[pos][cnt][tight];
            }
            long long res = 0;
            int limit = tight ? (s[pos] - '0') : 1;
            for (int d = 0; d <= limit; ++d) {
                int new_tight = tight && (d == limit);
                int new_cnt = cnt + (d == 1);
                res += dfs(pos + 1, new_cnt, new_tight);
            }
            return dp[pos][cnt][tight] = res;
        };

        total += dfs(0, 0, 1);
    }
    return total;
}
